import{_ as i,o as a,c as e,ai as t}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"install.md","filePath":"install.md"}'),l={name:"install.md"};function h(n,s,r,d,o,p){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h1><p>fixvr ships a single udev rule file (<code>99-valve-index-reboot.rules</code>) and a helper install script.<br> Pick the method that matches your distro.</p><h2 id="automatic-install-script" tabindex="-1">Automatic - install script <a class="header-anchor" href="#automatic-install-script" aria-label="Permalink to “Automatic - install script”">​</a></h2><p>The easiest way on any distro. Clone the repo and run the script:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/MiguVT/fixvr/refs/heads/main/src/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p>The script auto-detects your distro:</p><table tabindex="0"><thead><tr><th>Distro family</th><th>What happens</th></tr></thead><tbody><tr><td>Arch / Manjaro / EndeavourOS / Garuda</td><td>Installs the <code>fixvr</code> AUR package via <strong>paru</strong> or <strong>yay</strong></td></tr><tr><td>Debian / Ubuntu / Mint / Pop!_OS</td><td>Copies the rule and reloads udev</td></tr><tr><td>Fedora / RHEL / openSUSE / any other</td><td>Copies the rule and reloads udev</td></tr></tbody></table><blockquote><p><strong>AUR helper</strong> — If neither <code>paru</code> nor <code>yay</code> is found, the script will offer to install paru for you.</p></blockquote><h2 id="arch-based-aur" tabindex="-1">Arch-based (AUR) <a class="header-anchor" href="#arch-based-aur" aria-label="Permalink to “Arch-based (AUR)”">​</a></h2><p>Install with your preferred AUR helper:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-65" id="tab-66" checked><label data-title="paru" for="tab-66">paru</label><input type="radio" name="group-65" id="tab-67"><label data-title="yay" for="tab-67">yay</label></div><div class="blocks"><div class="language-bash active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">paru</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fixvr</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yay</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fixvr</span></span></code></pre></div></div></div><h2 id="manual-all-distros" tabindex="-1">Manual (all distros) <a class="header-anchor" href="#manual-all-distros" aria-label="Permalink to “Manual (all distros)”">​</a></h2><p>Download and install the rule file, then reload udev:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/MiguVT/fixvr/main/src/99-valve-index-reboot.rules</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/udev/rules.d/99-valve-index-reboot.rules</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udevadm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> control</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload-rules</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udevadm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trigger</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --subsystem-match=usb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --subsystem-match=hidraw</span></span></code></pre></div><p>Reconnect your Valve Index — the fix is now active.</p><h2 id="uninstall" tabindex="-1">Uninstall <a class="header-anchor" href="#uninstall" aria-label="Permalink to “Uninstall”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/udev/rules.d/99-valve-index-reboot.rules</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> udevadm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> control</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload-rules</span></span></code></pre></div><p>On Arch (AUR):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">paru</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fixvr</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # or: yay -R fixvr</span></span></code></pre></div><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to “How it works”">​</a></h2><p>The udev rule matches the Valve Index HMD by its USB vendor/product ID (<code>28de:2300</code>). On the <code>add</code> event — i.e. each time the device is enumerated — it runs a short shell one-liner:</p><ol><li>Checks for a flag file <code>/tmp/.valve-index-rebooted</code>.</li><li>If the flag is absent, it writes a 64-byte HID reboot payload (<code>\\x16\\x01</code> followed by zeroes) directly to the <code>hidraw</code> device node, then creates the flag file.</li><li>The HMD reboots its HID layer, re-reads the EDID correctly, and presents itself at the right resolution.</li></ol><p>Because <code>/tmp</code> is cleared every boot, the flag is always absent on the first plug-in of each session, and always present for subsequent plug-ins, preventing double-reboots.</p>`,23)])])}const g=i(l,[["render",h]]);export{c as __pageData,g as default};
